#include <stdio.h>
int main(){
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &N) != 1) break;
        if (N % 3 == 0 && N % 5 == 0) {
            printf("Divisible by both 3 and 5\n");
        } else {
            printf("Not divisible by both 3 and 5\n");
        }
    }
    return 0;
}

